// Generates the branded Squirrel installer splash GIF.
// Run:  node scripts/generate-install-gif.mjs
// Output: resources/install-splash.gif  (413x316, dark bg + orange logo)

import { createCanvas, loadImage } from 'canvas'
import GIFEncoder from 'gif-encoder-2'
import fs from 'fs'
import path from 'path'
import { fileURLToPath } from 'url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const OUT_PATH = path.join(__dirname, '..', 'resources', 'install-splash.gif')

const WIDTH = 413
const HEIGHT = 316
const FRAMES = 60
const DELAY = 33 // ~30 fps

const BG = '#121212'
const ORANGE = '#E27927'
const TEXT_COLOR = '#aaaaaa'

// Build an SVG of just the logo mark in orange on transparent background.
// The path is extracted from icon-source.svg; we re-color it here.
function buildLogoSvg(size) {
  return `<svg width="${size}" height="${size}" viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg">
    <path d="M29.5687 15.3464L26.5959 13.9421L29.4981 15.825L29.4223 16.5873L26.76 14.2029C26.7456 14.2644 26.7939 14.2807 26.8247 14.3173C27.0822 14.6227 27.4411 14.9201 27.7234 15.215C28.283 15.7988 28.8216 16.4062 29.3674 17.0031C29.3844 17.0633 29.2713 17.6262 29.2406 17.7131C29.2282 17.7484 29.2242 17.7909 29.1772 17.7962L26.7593 14.4651L29.0536 18.2956L29.0576 18.378L28.785 19.1685L27.5711 16.4134L26.3671 14.0081C26.9848 16.3454 27.5502 18.6977 27.9999 21.0762C27.9928 21.1547 27.6221 21.7986 27.5509 21.9019C27.5313 21.9307 27.5561 21.9627 27.4783 21.9444C27.3188 20.0923 27.0319 18.2545 26.7495 16.4186L26.4985 15.0862C26.6103 16.1819 26.775 17.2731 26.89 18.3689C27.0306 19.7078 27.1188 21.0527 27.241 22.3929L26.5639 23.3488C26.5377 23.1762 26.5926 23.0088 26.5978 22.8441C26.6671 20.6173 26.558 18.2989 26.4331 16.0813C26.4083 15.6354 26.3841 15.1882 26.3678 14.7423C26.3664 14.7031 26.3926 14.6207 26.3357 14.6285C26.3423 15.0365 26.3266 15.4464 26.3338 15.8544C26.3665 17.6732 26.3338 19.4895 26.271 21.309C26.1436 22.1347 26.2298 23.0716 26.1043 23.8862C26.0893 23.9816 25.8174 24.268 25.7311 24.3622C25.5736 24.5341 25.3977 24.6962 25.2245 24.8518C25.7396 21.6045 26.0547 18.3225 26.2383 15.0385L26.2043 14.6939C25.9089 18.3113 25.365 21.9104 24.6029 25.4553L23.5087 26.3209L23.4616 26.2745C24.6075 22.5433 25.4611 18.7232 26.1017 14.8698L26.0736 14.7273C25.2317 18.852 24.0231 22.8924 22.5948 26.8452C22.5269 26.976 22.0196 27.2336 21.8595 27.3186C21.6791 27.4147 21.4784 27.5173 21.2928 27.601C21.2039 27.6416 21.0718 27.7089 20.977 27.7096C22.5896 24.3798 23.993 20.9376 25.1591 17.4215C25.5069 16.3722 25.8671 15.2693 26.1547 14.2036C26.1664 14.1598 26.2403 13.9891 26.1717 13.9754C23.459 19.3064 20.1312 24.3255 16.3047 28.9171C15.404 29.0139 14.4548 28.9877 13.5613 28.8524L15.2445 27.2689C18.752 23.7953 21.9588 20.0216 24.7931 15.978L25.9095 14.3017C25.3781 14.9156 24.8911 15.5811 24.3734 16.2114C20.6332 20.7689 16.3655 24.927 11.7069 28.5359C11.1872 28.4418 10.6466 28.2672 10.1459 28.0848C9.60339 27.8867 9.07393 27.6461 8.56212 27.382C14.9091 23.7482 20.7901 19.292 25.9422 14.1055L23.2603 16.2088C18.1081 20.1066 12.5357 23.458 6.63579 26.1104L6.50636 26.1084C5.50561 25.3677 4.62513 24.4798 3.82636 23.5286L3.9048 23.4769C10.9277 21.4142 17.6924 18.5304 24.1028 15.026L26.2043 13.8126C25.1199 13.9068 24.0375 14.0375 22.9537 14.1389C15.5589 14.8306 8.14116 15.3418 0.722141 15.674C0.647624 14.3749 0.702531 13.0581 0.969878 11.7852L7.01098 12.1141C13.3423 12.5495 19.6697 13.0555 25.9756 13.7466L25.8847 13.6917C19.8652 12.2749 13.7829 11.1255 7.66007 10.224L1.65164 9.43615C1.61896 9.39104 1.88108 8.7974 1.92553 8.69476C2.34191 7.73499 2.89686 6.83865 3.49953 5.98807L3.54071 5.97892C11.1977 7.79187 18.682 10.3188 25.8324 13.5792L25.9749 13.6158L24.0041 12.4344C18.0447 9.04388 11.7624 6.19924 5.23042 4.07835C5.21408 4.01494 5.25657 4.01559 5.28533 3.98682C6.12855 3.13951 7.21493 2.44977 8.2379 1.84109L8.30131 1.83847C13.6077 4.49351 18.6422 7.67681 23.3113 11.3315L25.7795 13.3223C21.0738 8.58557 15.7229 4.51443 10.0328 1.02581C10.8349 0.731608 11.6644 0.481861 12.5089 0.333451C12.6253 0.313184 13.1743 0.216423 13.2325 0.241921C17.393 3.67039 21.2176 7.50421 24.6349 11.6741C25.0291 12.1553 25.3958 12.6685 25.8115 13.1268L24.7931 11.5812C22.3863 8.1508 19.7442 4.88251 16.8616 1.84109C16.3237 1.2736 15.738 0.736839 15.2111 0.160197C15.1981 0.145814 15.136 0.103317 15.1784 0.0948181C16.0308 0.106586 16.8806 0.184387 17.7179 0.332143L17.7937 0.387062C20.9568 4.50332 23.7917 8.88239 26.1396 13.5184C26.1978 13.5263 26.171 13.4458 26.1645 13.4118C26.0821 12.983 25.8841 12.424 25.7559 11.9912C24.7382 8.55615 23.4838 5.18849 22.0562 1.90712L22.0719 1.85874C22.2955 2.01107 22.5432 2.12549 22.772 2.26932C22.9112 2.35693 23.3524 2.62433 23.4126 2.73939C24.4558 5.91942 25.3579 9.15306 26.0096 12.4403C26.0658 12.4482 26.0442 12.3632 26.0416 12.3272C26.0318 12.1919 25.9899 12.0193 25.9664 11.8794C25.6174 9.80424 25.1533 7.69446 24.648 5.65333C24.4434 4.8276 24.1741 4.00709 23.9852 3.1807C23.9813 3.1624 23.9754 3.12774 24.0002 3.13297C24.3212 3.41868 24.6957 3.66058 24.9663 3.99598C25.5206 6.93933 25.9664 9.90884 26.2056 12.8986L26.2396 12.5874C26.1553 11.4459 26.1063 10.3005 26.0096 9.1596C25.8782 7.61797 25.6598 6.08875 25.4879 4.553C25.4847 4.52293 25.4709 4.44317 25.52 4.48828L26.205 5.30617C26.2285 5.92727 26.2455 6.54771 26.2697 7.16816C26.3377 8.93077 26.3919 10.7254 26.3044 12.4907C26.2985 12.6044 26.307 12.7195 26.3044 12.8332L26.3691 12.5227C26.49 10.2678 26.5737 8.00893 26.5658 5.74617C26.6854 5.91746 26.9953 6.22866 27.0626 6.40846C27.1031 6.51633 27.0927 6.66082 27.0894 6.77654C27.0613 7.72846 26.9266 8.8229 26.8266 9.78005C26.7155 10.8431 26.5475 11.9016 26.4351 12.9647L26.9848 9.93826L27.3862 7.00864C27.4156 6.96352 27.4201 6.93803 27.4633 6.98837C27.5064 7.03871 27.8221 7.58658 27.8254 7.6232C27.413 9.62837 26.894 11.608 26.3697 13.5851L27.443 11.4413L28.4935 9.07853L28.7412 9.66498V9.79705L26.6639 13.2262L28.885 10.1723L29.0321 10.5809L29.0759 10.851L26.6639 13.4217L29.1635 11.2668C29.2308 11.2563 29.2027 11.2753 29.2157 11.3112C29.2792 11.4851 29.2798 11.7231 29.3452 11.9049L26.3697 13.7485L29.5387 13.4223L29.5713 14.1735L26.6639 13.863L29.572 14.6142V15.349L29.5687 15.3464Z" fill="${ORANGE}"/>
  </svg>`
}

async function loadLogo() {
  const svgBuffer = Buffer.from(buildLogoSvg(120))
  return loadImage(svgBuffer)
}

function drawFrame(ctx, logoImg, frameIndex) {
  ctx.fillStyle = BG
  ctx.fillRect(0, 0, WIDTH, HEIGHT)

  // Draw logo centered in upper portion
  const logoX = (WIDTH - logoImg.width) / 2
  const logoY = 60
  ctx.drawImage(logoImg, logoX, logoY)

  // "Installing Shogo..." text
  ctx.fillStyle = TEXT_COLOR
  ctx.font = '15px sans-serif'
  ctx.textAlign = 'center'
  ctx.fillText('Installing Shogo\u2026', WIDTH / 2, logoY + logoImg.height + 35)

  // Animated progress bar
  const barY = 240
  const barH = 3
  const barTrackW = 200
  const barX = (WIDTH - barTrackW) / 2

  // Track (subtle)
  ctx.fillStyle = 'rgba(255, 255, 255, 0.08)'
  roundRect(ctx, barX, barY, barTrackW, barH, barH / 2)
  ctx.fill()

  // Sliding indicator with sine wave sweep
  const t = frameIndex / FRAMES
  const eased = (Math.sin(t * Math.PI * 2 - Math.PI / 2) + 1) / 2
  const indicatorW = 60
  const indicatorX = barX + eased * (barTrackW - indicatorW)

  ctx.fillStyle = ORANGE
  roundRect(ctx, indicatorX, barY, indicatorW, barH, barH / 2)
  ctx.fill()
}

function roundRect(ctx, x, y, w, h, r) {
  ctx.beginPath()
  ctx.moveTo(x + r, y)
  ctx.lineTo(x + w - r, y)
  ctx.quadraticCurveTo(x + w, y, x + w, y + r)
  ctx.lineTo(x + w, y + h - r)
  ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h)
  ctx.lineTo(x + r, y + h)
  ctx.quadraticCurveTo(x, y + h, x, y + h - r)
  ctx.lineTo(x, y + r)
  ctx.quadraticCurveTo(x, y, x + r, y)
  ctx.closePath()
}

async function main() {
  const logoImg = await loadLogo()

  const canvas = createCanvas(WIDTH, HEIGHT)
  const ctx = canvas.getContext('2d')
  const encoder = new GIFEncoder(WIDTH, HEIGHT, 'neuquant', true)

  encoder.setDelay(DELAY)
  encoder.setRepeat(0)
  encoder.setQuality(10)
  encoder.start()

  for (let i = 0; i < FRAMES; i++) {
    drawFrame(ctx, logoImg, i)
    encoder.addFrame(ctx)
  }

  encoder.finish()
  const buffer = encoder.out.getData()
  fs.writeFileSync(OUT_PATH, buffer)
  console.log(`Generated ${OUT_PATH} (${(buffer.length / 1024).toFixed(1)} KB, ${FRAMES} frames)`)
}

main().catch((err) => { console.error(err); process.exit(1) })
